// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000009

int F[1000005];

int pointInPolygon(int x, int y, int n, int *xv, int *yv) {
    int c = 0;
    for (int i = 0, j = n - 1; i < n; j = i++) {
        if (((yv[i] > y) != (yv[j] > y)) && (x < (xv[j] - xv[i]) * (y - yv[i]) / (yv[j] - yv[i]) + xv[i]))
            c = !c;
    }
    return c;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, a, b, c, d, F0, F1, F2, F3;
        scanf("%d %d %d %d %d %d %d %d %d", &N, &a, &b, &c, &d, &F0, &F1, &F2, &F3);
        F[0] = F0;
        F[1] = F1;
        F[2] = F2;
        F[3] = F3;
        for (int i = 4; i < 1000005; i++) {
            F[i] = (a * F[i - 1] + b * F[i - 2] + c * F[i - 3] + d * F[i - 4]) % MOD;
        }
        int *xv = (int *)malloc(N * sizeof(int));
        int *yv = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &xv[i], &yv[i]);
        }
        long long ans = 0;
        for (int x = 0; x <= 1000000; x++) {
            for (int y = 0; y <= 1000000; y++) {
                if (pointInPolygon(x, y, N, xv, yv)) {
                    ans = (ans + F[x + y]) % MOD;
                }
            }
        }
        printf("%lld\n", ans);
        free(xv);
        free(yv);
    }
    return 0;
}

